from collections import defaultdict, deque

def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    nodes = set(deps)
    for pres in deps.values():
        nodes.update(pres)

    in_degree = {node: 0 for node in nodes}
    graph = defaultdict(list)

    for task, pres in deps.items():
        seen = set()
        for p in pres:
            if p in seen:
                continue
            seen.add(p)
            graph[p].append(task)
            in_degree[task] += 1

    ready = sorted(node for node, deg in in_degree.items() if deg == 0)
    result = []

    while ready:
        layer = ready
        result.append(layer)
        next_ready = []
        for node in layer:
            for nxt in graph[node]:
                in_degree[nxt] -= 1
                if in_degree[nxt] == 0:
                    next_ready.append(nxt)
        ready = sorted(next_ready)

    if sum(len(layer) for layer in result) != len(nodes):
        return []
    return result

