def solve(s: str) -> bool:
    stack = []
    in_quote = ''
    i = 0
    n = len(s)
    pairs = {'(': ')', '[': ']', '{': '}'}
    while i < n:
        c = s[i]
        if in_quote:
            if c == '\\' and i + 1 < n and s[i + 1] == in_quote:
                i += 2
                continue
            if c == in_quote:
                in_quote = ''
        else:
            if c == '\\' and i + 1 < n and s[i + 1] in ("'", '"'):
                i += 2
                continue
            if c in ("'", '"'):
                in_quote = c
            elif c in pairs:
                stack.append(pairs[c])
            elif c in pairs.values():
                if not stack or stack[-1] != c:
                    return False
                stack.pop()
        i += 1
    return not stack
