    s = expr
    n = len(s)
    i = 0

    def skip():
        nonlocal i
        while i < n and s[i] == ' ':
            i += 1

    def parse_expr():
        nonlocal i
        skip()
        val = parse_term()
        while True:
            skip()
            if i < n and s[i] in '+-':
                op = s[i]
                i += 1
                if op == '+':
                    val += parse_term()
                else:
                    val -= parse_term()
            else:
                return val

    def parse_term():
        nonlocal i
        skip()
        sign = 1
        while i < n and s[i] in '+-':
            if s[i] == '-':
                sign = -sign
            i += 1
            skip()
        return sign * parse_factor()

    def parse_factor():
        nonlocal i
        skip()
        if i < n and s[i] == '(':
            i += 1
            val = parse_expr()
            skip()
            if i < n and s[i] == ')':
                i += 1
            return val
        val = 0
        while i < n and s[i].isdigit():
            val = val * 10 + int(s[i])
            i += 1
        return val

    return parse_expr()
